USE DataExplorationDB;

CREATE EXTERNAL DATA SOURCE HcmuteLake
WITH ( LOCATION = 'https://dlhcmute.dfs.core.windows.net' );

CREATE LOGIN data_explorer WITH PASSWORD = 'My Very Strong Password 1234!';
GO

CREATE USER data_explorer FOR LOGIN data_explorer;
GO

GRANT ADMINISTER DATABASE BULK OPERATIONS TO data_explorer;
GO

SELECT
    TOP 100 *
FROM
    OPENROWSET(
        BULK '/data/Customer/**',
        DATA_SOURCE = 'HcmuteLake',
        FORMAT = 'CSV',
        PARSER_VERSION = '2.0',
        HEADER_ROW = TRUE 
    ) AS [result];
